/*!
 * Local chart runtime (Chart-compatible subset) for offline Electron packaging.
 * Supports line/bar/doughnut, axes/ticks, legend, and hover tooltip.
 */
(function (global) {
  'use strict';

  function num(v) {
    var n = Number(v);
    return Number.isFinite(n) ? n : 0;
  }

  function maxLen(arr) {
    var m = 0;
    for (var i = 0; i < arr.length; i++) m = Math.max(m, (arr[i] || []).length || 0);
    return m;
  }

  function makeTooltip() {
    var el = document.createElement('div');
    el.style.position = 'fixed';
    el.style.zIndex = '99999';
    el.style.pointerEvents = 'none';
    el.style.padding = '6px 8px';
    el.style.borderRadius = '6px';
    el.style.fontSize = '12px';
    el.style.color = '#fff';
    el.style.background = 'rgba(15,23,42,0.92)';
    el.style.boxShadow = '0 4px 12px rgba(0,0,0,0.25)';
    el.style.display = 'none';
    document.body.appendChild(el);
    return el;
  }

  function extent(datasets) {
    var min = 0;
    var max = 0;
    for (var i = 0; i < datasets.length; i++) {
      var ds = datasets[i].data || [];
      for (var j = 0; j < ds.length; j++) {
        var v = num(ds[j]);
        if (v < min) min = v;
        if (v > max) max = v;
      }
    }
    if (min === max) {
      if (max === 0) max = 1;
      else min = 0;
    }
    return { min: min, max: max };
  }

  function canvasSize(canvas) {
    var ratio = global.devicePixelRatio || 1;
    var cssW = canvas.clientWidth || 640;
    var cssH = canvas.clientHeight || 320;
    canvas.width = Math.max(1, Math.floor(cssW * ratio));
    canvas.height = Math.max(1, Math.floor(cssH * ratio));
    return { w: cssW, h: cssH, ratio: ratio };
  }

  function drawLegend(ctx, datasets, left, top, width) {
    var x = left;
    var y = top - 18;
    ctx.font = '11px sans-serif';
    for (var i = 0; i < datasets.length; i++) {
      var ds = datasets[i];
      var text = ds.label || ('系列 ' + (i + 1));
      var color = ds.borderColor || ds.backgroundColor || '#3b82f6';
      ctx.fillStyle = color;
      ctx.fillRect(x, y - 8, 10, 10);
      ctx.fillStyle = '#334155';
      ctx.fillText(text, x + 14, y);
      x += ctx.measureText(text).width + 28;
      if (x > left + width - 120) break;
    }
  }

  function buildScale(min, max, ticks) {
    var span = max - min;
    var step = span / ticks;
    var values = [];
    for (var i = 0; i <= ticks; i++) values.push(min + step * i);
    return values;
  }

  function drawAxes(ctx, area, min, max, labels) {
    var left = area.left, right = area.right, top = area.top, bottom = area.bottom;
    var width = right - left, height = bottom - top;
    ctx.strokeStyle = '#e2e8f0';
    ctx.fillStyle = '#64748b';
    ctx.lineWidth = 1;
    ctx.font = '11px sans-serif';

    var yTicks = buildScale(min, max, 5);
    for (var i = 0; i < yTicks.length; i++) {
      var v = yTicks[i];
      var y = bottom - ((v - min) / (max - min || 1)) * height;
      ctx.beginPath();
      ctx.moveTo(left, y);
      ctx.lineTo(right, y);
      ctx.stroke();
      ctx.fillText(Math.round(v).toLocaleString('ja-JP'), 6, y + 4);
    }

    var n = Math.max(labels.length, 1);
    var maxLabels = Math.min(n, 8);
    var step = Math.max(1, Math.ceil(n / maxLabels));
    for (var j = 0; j < n; j += step) {
      var x = left + (j * width) / Math.max(n - 1, 1);
      ctx.beginPath();
      ctx.moveTo(x, top);
      ctx.lineTo(x, bottom);
      ctx.stroke();
      var t = String(labels[j] || '');
      ctx.fillText(t, x - Math.min(20, t.length * 3), bottom + 16);
    }

    ctx.strokeStyle = '#94a3b8';
    ctx.beginPath();
    ctx.moveTo(left, top);
    ctx.lineTo(left, bottom);
    ctx.lineTo(right, bottom);
    ctx.stroke();
  }

  function Chart(canvas, config) {
    this.canvas = canvas;
    this.ctx = canvas && canvas.getContext ? canvas.getContext('2d') : null;
    this.config = config || {};
    this.type = this.config.type || 'line';
    this._points = [];
    this._hoverIndex = -1;
    this._hoverPie = -1;
    this._tooltip = makeTooltip();
    this._boundMove = this._onMouseMove.bind(this);
    this._boundLeave = this._onMouseLeave.bind(this);
    if (this.canvas) {
      this.canvas.addEventListener('mousemove', this._boundMove);
      this.canvas.addEventListener('mouseleave', this._boundLeave);
    }
    this._draw();
  }

  Chart.prototype._getData = function () {
    var data = this.config.data || {};
    return {
      labels: data.labels || [],
      datasets: data.datasets || []
    };
  };

  Chart.prototype._clear = function () {
    if (!this.canvas || !this.ctx) return;
    var s = canvasSize(this.canvas);
    this.ctx.setTransform(s.ratio, 0, 0, s.ratio, 0, 0);
    this.ctx.clearRect(0, 0, s.w, s.h);
    return s;
  };

  Chart.prototype._drawLineOrBar = function (kind, s) {
    var ctx = this.ctx;
    var data = this._getData();
    var labels = data.labels;
    var datasets = data.datasets;
    var ext = extent(datasets);
    var area = { left: 56, right: s.w - 12, top: 28, bottom: s.h - 30 };
    var w = area.right - area.left;
    var h = area.bottom - area.top;
    this._points = [];

    drawAxes(ctx, area, ext.min, ext.max, labels);
    drawLegend(ctx, datasets, area.left, area.top, w);

    var n = Math.max(maxLen(datasets.map(function (d) { return d.data || []; })), labels.length, 1);
    var groupW = w / Math.max(n, 1);
    var barW = Math.max(4, (groupW * 0.75) / Math.max(datasets.length, 1));

    for (var i = 0; i < datasets.length; i++) {
      var ds = datasets[i];
      var vals = ds.data || [];
      var color = ds.borderColor || ds.backgroundColor || '#3b82f6';
      ctx.strokeStyle = color;
      ctx.fillStyle = ds.backgroundColor || color;
      ctx.lineWidth = 2;
      if (kind === 'line') ctx.beginPath();

      for (var j = 0; j < vals.length; j++) {
        var v = num(vals[j]);
        var x = area.left + (j * w) / Math.max(n - 1, 1);
        var y = area.bottom - ((v - ext.min) / (ext.max - ext.min || 1)) * h;
        if (kind === 'line') {
          if (j === 0) ctx.moveTo(x, y);
          else ctx.lineTo(x, y);
          this._points.push({ x: x, y: y, label: labels[j], value: v, datasetLabel: ds.label || ('系列 ' + (i + 1)), color: color });
        } else {
          var baseY = area.bottom - ((0 - ext.min) / (ext.max - ext.min || 1)) * h;
          var bh = Math.abs(y - baseY);
          var bx = area.left + j * groupW + groupW * 0.12 + i * barW;
          var by = v >= 0 ? y : baseY;
          ctx.fillRect(bx, by, barW - 1, Math.max(1, bh));
          this._points.push({ x: bx + (barW - 1) / 2, y: by, label: labels[j], value: v, datasetLabel: ds.label || ('系列 ' + (i + 1)), color: color });
        }
      }

      if (kind === 'line') {
        ctx.stroke();
        for (var k = 0; k < vals.length; k++) {
          var pv = num(vals[k]);
          var px = area.left + (k * w) / Math.max(n - 1, 1);
          var py = area.bottom - ((pv - ext.min) / (ext.max - ext.min || 1)) * h;
          ctx.beginPath();
          ctx.fillStyle = color;
          ctx.arc(px, py, 2.5, 0, Math.PI * 2);
          ctx.fill();
        }
      }
    }

    if (this._hoverIndex >= 0 && this._points[this._hoverIndex]) {
      var p = this._points[this._hoverIndex];
      ctx.strokeStyle = 'rgba(15,23,42,0.25)';
      ctx.beginPath();
      ctx.moveTo(p.x, area.top);
      ctx.lineTo(p.x, area.bottom);
      ctx.stroke();
    }
  };

  Chart.prototype._drawDoughnut = function (s) {
    var ctx = this.ctx;
    var data = this._getData();
    var ds = data.datasets[0] || { data: [] };
    var values = ds.data || [];
    var total = values.reduce(function (sum, v) { return sum + Math.max(0, num(v)); }, 0) || 1;
    var cx = s.w / 2, cy = s.h / 2;
    var outer = Math.max(30, Math.min(s.w, s.h) * 0.35);
    var inner = outer * 0.58;
    var start = -Math.PI / 2;
    var colors = ds.backgroundColor || [];
    this._points = [];

    for (var i = 0; i < values.length; i++) {
      var value = Math.max(0, num(values[i]));
      var end = start + Math.PI * 2 * (value / total);
      var color = colors[i] || '#94a3b8';
      ctx.beginPath();
      ctx.moveTo(cx, cy);
      ctx.fillStyle = color;
      ctx.arc(cx, cy, outer, start, end);
      ctx.closePath();
      ctx.fill();
      this._points.push({
        start: start, end: end, cx: cx, cy: cy, inner: inner, outer: outer,
        label: data.labels[i] || ('項目 ' + (i + 1)),
        datasetLabel: ds.label || '内訳',
        value: value,
        color: color
      });
      start = end;
    }

    ctx.beginPath();
    ctx.fillStyle = '#fff';
    ctx.arc(cx, cy, inner, 0, Math.PI * 2);
    ctx.fill();
  };

  Chart.prototype._draw = function () {
    if (!this.canvas || !this.ctx) return;
    var s = this._clear();
    if (!s) return;
    if (this.type === 'bar') this._drawLineOrBar('bar', s);
    else if (this.type === 'doughnut') this._drawDoughnut(s);
    else this._drawLineOrBar('line', s);
  };

  Chart.prototype._onMouseMove = function (ev) {
    if (!this.canvas) return;
    var rect = this.canvas.getBoundingClientRect();
    var x = ev.clientX - rect.left;
    var y = ev.clientY - rect.top;
    var nearest = -1;
    var best = Infinity;

    if (this.type === 'doughnut') {
      var hover = -1;
      for (var i = 0; i < this._points.length; i++) {
        var p = this._points[i];
        var dx = x - p.cx;
        var dy = y - p.cy;
        var r = Math.sqrt(dx * dx + dy * dy);
        var a = Math.atan2(dy, dx);
        if (a < -Math.PI / 2) a += Math.PI * 2;
        var inRing = r >= p.inner && r <= p.outer;
        var inArc = a >= p.start && a <= p.end;
        if (inRing && inArc) { hover = i; break; }
      }
      this._hoverPie = hover;
      if (hover >= 0) {
        var pp = this._points[hover];
        this._tooltip.innerHTML = '<b>' + pp.label + '</b><br>' + pp.datasetLabel + ': ' + Math.round(pp.value).toLocaleString('ja-JP');
        this._tooltip.style.left = ev.clientX + 12 + 'px';
        this._tooltip.style.top = ev.clientY + 12 + 'px';
        this._tooltip.style.display = 'block';
      } else {
        this._tooltip.style.display = 'none';
      }
      return;
    }

    for (var j = 0; j < this._points.length; j++) {
      var pt = this._points[j];
      var d = Math.abs(pt.x - x) + Math.abs(pt.y - y) * 0.35;
      if (d < best) {
        best = d;
        nearest = j;
      }
    }
    if (best < 36) {
      this._hoverIndex = nearest;
      var pnt = this._points[nearest];
      this._tooltip.innerHTML = '<b>' + (pnt.label || '') + '</b><br>' + pnt.datasetLabel + ': ' + Math.round(pnt.value).toLocaleString('ja-JP');
      this._tooltip.style.left = ev.clientX + 12 + 'px';
      this._tooltip.style.top = ev.clientY + 12 + 'px';
      this._tooltip.style.display = 'block';
      this._draw();
    } else {
      this._hoverIndex = -1;
      this._tooltip.style.display = 'none';
      this._draw();
    }
  };

  Chart.prototype._onMouseLeave = function () {
    this._hoverIndex = -1;
    this._hoverPie = -1;
    this._tooltip.style.display = 'none';
    this._draw();
  };

  Chart.prototype.destroy = function () {
    if (this.canvas) {
      this.canvas.removeEventListener('mousemove', this._boundMove);
      this.canvas.removeEventListener('mouseleave', this._boundLeave);
    }
    if (this._tooltip && this._tooltip.parentNode) {
      this._tooltip.parentNode.removeChild(this._tooltip);
    }
    this._points = [];
    this._clear();
  };

  global.Chart = Chart;
})(typeof window !== 'undefined' ? window : globalThis);
